import React from 'react';

const StatDetailsModal = ({ onClose, title, filterId, history }) => {
  const activeThreats = history ? history.filter(t => t.severity === 'CRITICAL') : [];
  const blockedIps = history ? history.map(t => t.source_ip) : [];
  const uniqueCountries = history ? [...new Set(history.map(t => t.origin_country))] : [];

  return (
    <div style={{ position: 'fixed', top: 0, left: 0, width: '100%', height: '100%', background: 'rgba(11, 15, 25, 0.95)', display: 'flex', justifyContent: 'center', alignItems: 'center', zIndex: 1000 }}>
      <div style={{ background: '#0f172a', padding: '30px', borderRadius: '12px', width: '70%', minHeight: '400px', border: '1px solid #475569', boxShadow: '0 0 40px rgba(0,0,0,0.5)', color: 'white' }}>
        
        <div style={{ display: 'flex', justifyContent: 'space-between', borderBottom: '1px solid #334155', paddingBottom: '15px', marginBottom: '20px' }}>
          <h2 style={{ margin: 0 }}>📊 Analytics: {title}</h2>
          <button onClick={onClose} style={{ background: 'transparent', border: 'none', cursor: 'pointer', color: '#ef4444', fontSize: '24px' }}>&times;</button>
        </div>

        <div style={{ color: '#cbd5e1' }}>
          {filterId === 'total' && (
            <div>
              <h3>System Overview</h3>
              <p>Total packets analyzed by CortexShield AI since boot.</p>
              <div style={{ display: 'flex', gap: '20px', marginTop: '20px' }}>
                <div style={{ background: '#1e293b', padding: '20px', borderRadius: '8px', flex: 1 }}>DDoS Mitigated: 45%</div>
                <div style={{ background: '#1e293b', padding: '20px', borderRadius: '8px', flex: 1 }}>Phishing Blocked: 30%</div>
              </div>
            </div>
          )}

          {filterId === 'active' && (
            <div>
              <h3 style={{ color: '#eab308' }}>Live Critical Intrusions ({activeThreats.length})</h3>
              {activeThreats.length === 0 ? <p>No active critical threats.</p> : activeThreats.map((threat, i) => (
                <div key={i} style={{ background: '#1e293b', margin: '10px 0', padding: '15px', borderRadius: '6px', borderLeft: '4px solid #eab308' }}>
                  <strong>{threat.attack_type}</strong> (IP: {threat.source_ip})
                </div>
              ))}
            </div>
          )}

          {filterId === 'blocked' && (
            <div>
              <h3 style={{ color: '#10b981' }}>Firewall Blocklist</h3>
              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '10px' }}>
                {[...new Set(blockedIps)].slice(0, 10).map((ip, i) => (
                  <div key={i} style={{ background: '#1e293b', padding: '10px', borderRadius: '6px', fontFamily: 'monospace' }}>🚫 {ip}</div>
                ))}
              </div>
            </div>
          )}

          {filterId === 'regions' && (
            <div>
              <h3 style={{ color: '#8b5cf6' }}>Affected Regions</h3>
              {uniqueCountries.map((country, i) => (
                <div key={i} style={{ background: '#1e293b', margin: '5px 0', padding: '10px', borderRadius: '6px' }}>📍 {country}</div>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default StatDetailsModal;
